MIN_SUPPORTED_PYTHON = (3, 11)


def _python_version_label(version_info: tuple[int, ...] | object) -> str:
    major = getattr(version_info, "major", None)
    minor = getattr(version_info, "minor", None)
    micro = getattr(version_info, "micro", None)
    if major is not None and minor is not None:
        if micro is not None:
            return f"{major}.{minor}.{micro}"
        return f"{major}.{minor}"
    seq = tuple(version_info)  # type: ignore[arg-type]
    if len(seq) >= 3:
        return f"{seq[0]}.{seq[1]}.{seq[2]}"
    if len(seq) >= 2:
        return f"{seq[0]}.{seq[1]}"
    return ".".join(str(part) for part in seq)


def _require_supported_python(version_info: tuple[int, ...] | object | None = None) -> None:
    current = version_info or sys.version_info
    current_tuple = (
        current.major,
        current.minor,
    ) if hasattr(current, "major") else tuple(current[:2])  # type: ignore[index]
    if current_tuple < MIN_SUPPORTED_PYTHON:
        detected = _python_version_label(current)
        required = ".".join(str(part) for part in MIN_SUPPORTED_PYTHON)
        raise SystemExit(
            "The agent migration scripts require Python "
            f"{required}+; detected {detected}."
        )


_require_supported_python()


def _find_repo_root() -> Path:
    p = Path(__file__).resolve().parent
    while p != p.parent:
        if (p / ".git").exists() or (p / "package.json").exists():
            return p
        p = p.parent
    raise RuntimeError("Repository root not found")


